// Provide a minimal Phoenix v2 event for manual testing.
return [{
  json: {
    version: '2.0.0',
    article: {
      id: 'manual-001',
      source: 'manual',
      url: 'https://example.com/manual-001',
      title: 'Phoenix v2 Contract Test',
      language: 'zh-TW',
      content: 'Minimal content for validating the Phoenix v2 event contract.',
      images: [],
      tags: []
    },
    metadata: {
      eventType: 'content.received',
      timezone: 'Asia/Taipei',
      language: 'zh-TW',
      status: 'received'
    }
  }
}];

// Normalize and validate the Phoenix Event Contract v2.
const input = $input.first().json;
const body = input.body ?? input;

const fail = (message, details = []) => {
  const error = new Error(message);
  error.name = 'PHOENIX_CONTRACT_INVALID';
  error.details = details;
  throw error;
};

if (!body || typeof body !== 'object' || Array.isArray(body)) {
  fail('Phoenix event must be an object');
}

const version = String(body.version ?? '2.0.0');
const major = Number(version.split('.')[0]);

if (major !== 2) {
  fail(`Unsupported Phoenix event version: ${version}`, [
    'Expected a 2.x.x version'
  ]);
}

const objectSections = [
  'article',
  'analysis',
  'research',
  'styleRag',
  'writingMemoryContext',
  'promptContext',
  'draft',
  'review',
  'publication',
  'feedback',
  'metadata'
];

for (const section of objectSections) {
  if (
    body[section] !== undefined &&
    (typeof body[section] !== 'object' || body[section] === null || Array.isArray(body[section]))
  ) {
    fail(`${section} must be an object`);
  }
}

const now = new Date().toISOString();
const existingMetadata = body.metadata ?? {};
const history = Array.isArray(existingMetadata.history)
  ? existingMetadata.history
  : [];

const eventId = existingMetadata.eventId ||
  `evt:${Date.now()}:${Math.random().toString(36).slice(2, 10)}`;

const normalized = {
  ...body,
  version,
  article: body.article ?? {},
  analysis: body.analysis ?? {},
  research: body.research ?? {},
  styleRag: body.styleRag ?? {},
  writingMemoryContext: body.writingMemoryContext ?? {},
  promptContext: body.promptContext ?? {},
  draft: body.draft ?? {},
  review: body.review ?? {},
  publication: body.publication ?? {},
  feedback: body.feedback ?? {},
  metadata: {
    ...existingMetadata,
    eventId,
    eventType: existingMetadata.eventType ?? 'phoenix.event',
    createdAt: existingMetadata.createdAt ?? now,
    updatedAt: now,
    timezone: existingMetadata.timezone ?? 'Asia/Taipei',
    language: existingMetadata.language ?? body.article?.language ?? 'zh-TW',
    currentWorkflow: 'shared-contract-validator',
    status: 'contract_valid',
    history: [
      ...history,
      {
        workflow: 'shared-contract-validator',
        version: '2.0.0',
        status: 'contract_valid',
        timestamp: now
      }
    ]
  }
};

if (
  normalized.article.url &&
  !/^https?:\/\//i.test(String(normalized.article.url))
) {
  fail('article.url must start with http:// or https://');
}

return [{ json: normalized }];
